  "inlineSchema": "// prisma/schema.prisma\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ----------------------------------------------------\n// ENUMS PARA INTEGRIDAD FINANCIERA Y FACTURACIÓN\n// ----------------------------------------------------\nenum TransactionType {\n  INCOME\n  EXPENSE\n}\n\nenum TransactionStatus {\n  PENDING\n  PAID\n  CANCELLED\n}\n\nenum RecurrenceFrequency {\n  MONTHLY\n  ANNUAL\n}\n\n// NUEVO: Enum para el estado de las facturas (Borradores vs SAT)\nenum InvoiceStatus {\n  DRAFT // Borrador (No timbrada)\n  TIMBRADA // Aprobada por el SAT\n  CANCELLED // Cancelada en el SAT\n}\n\n// 👤 MÓDULO AUTH\nmodel User {\n  id           String   @id @default(uuid())\n  username     String   @unique\n  passwordHash String\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n}\n\n// 📦 MÓDULO SERVICIOS Y CLIENTES\nmodel Service {\n  id           String                 @id @default(uuid())\n  name         String                 @unique\n  isActive     Boolean                @default(true)\n  transactions FinancialTransaction[]\n  createdAt    DateTime               @default(now())\n  updatedAt    DateTime               @updatedAt\n}\n\nmodel Client {\n  id                String                 @id @default(uuid())\n  firstName         String\n  lastName1         String\n  lastName2         String?\n  documentReminders DocumentReminder[]\n  rfc               String                 @unique\n  phone             String?\n  email             String?\n  isActive          Boolean                @default(true)\n  transactions      FinancialTransaction[]\n  subscriptions     Subscription[]\n  createdAt         DateTime               @default(now())\n  updatedAt         DateTime               @updatedAt\n}\n\n// ⏰ MÓDULO RECORDATORIOS\nmodel DocumentReminder {\n  id String @id @default(uuid())\n\n  // Relación con el Cliente\n  clientId String\n  client   Client @relation(fields: [clientId], references: [id], onDelete: Cascade)\n\n  documentType   String\n  rfc            String?\n  expirationDate DateTime\n  notified7Days  Boolean  @default(false)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// 🔄 MÓDULO SUSCRIPCIONES\nmodel Subscription {\n  id          String              @id @default(uuid())\n  clientId    String\n  client      Client              @relation(fields: [clientId], references: [id])\n  serviceName String\n  amount      Decimal             @db.Decimal(10, 2)\n  frequency   RecurrenceFrequency\n  startDate   DateTime\n  nextBilling DateTime\n  isActive    Boolean             @default(true)\n\n  // 👇 NUEVO: Relación para que la suscripción sepa cuáles son sus recibos generados\n  transactions FinancialTransaction[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// 💰 MÓDULO FINANZAS\nmodel FinancialTransaction {\n  id          String            @id @default(uuid())\n  type        TransactionType\n  amount      Decimal           @db.Decimal(10, 2)\n  description String\n  date        DateTime          @default(now())\n  status      TransactionStatus @default(PENDING)\n\n  clientId String?\n  client   Client? @relation(fields: [clientId], references: [id])\n\n  serviceId String?\n  service   Service? @relation(fields: [serviceId], references: [id])\n\n  // 👇 NUEVO: Relación para que el cobro sepa a qué suscripción pertenece\n  subscriptionId String?\n  subscription   Subscription? @relation(fields: [subscriptionId], references: [id], onDelete: SetNull)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// 📊 MÓDULO REPORTES\nmodel Report {\n  id          String   @id @default(uuid())\n  title       String\n  type        String\n  dataUrl     String?\n  generatedAt DateTime @default(now())\n  createdAt   DateTime @default(now())\n}\n\n// ====================================================\n// 🧾 MÓDULO FACTURACIÓN ELECTRÓNICA (CFDI 4.0)\n// ====================================================\n\nmodel BillingEmisor {\n  id            String            @id @default(uuid())\n  rfc           String            @unique\n  razonSocial   String\n  regimenFiscal String\n  codigoPostal  String\n  email         String?\n  // Relaciones: Aislamiento de datos por Emisor (Estilo inoWebs)\n  receptores    BillingReceptor[]\n  conceptos     BillingConcept[]\n  invoices      Invoice[]\n  createdAt     DateTime          @default(now())\n  updatedAt     DateTime          @updatedAt\n}\n\nmodel BillingReceptor {\n  id             String        @id @default(uuid())\n  emisorId       String\n  emisor         BillingEmisor @relation(fields: [emisorId], references: [id], onDelete: Cascade)\n  rfc            String\n  razonSocial    String\n  usoCfdiDefault String\n  regimenFiscal  String\n  codigoPostal   String\n  email          String?\n  invoices       Invoice[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Un emisor no puede tener el mismo RFC de cliente duplicado, pero diferentes emisores sí.\n  @@unique([emisorId, rfc])\n}\n\nmodel BillingConcept {\n  id                 String        @id @default(uuid())\n  emisorId           String\n  emisor             BillingEmisor @relation(fields: [emisorId], references: [id], onDelete: Cascade)\n  claveProdServ      String\n  noIdentificacion   String?\n  descripcion        String\n  claveUnidad        String\n  valorUnitario      Decimal       @db.Decimal(10, 2)\n  impuestoTrasladado Decimal       @db.Decimal(5, 4)\n  createdAt          DateTime      @default(now())\n  updatedAt          DateTime      @updatedAt\n}\n\nmodel Invoice {\n  id              String          @id @default(uuid())\n  emisorId        String\n  emisor          BillingEmisor   @relation(fields: [emisorId], references: [id])\n  receptorId      String\n  receptor        BillingReceptor @relation(fields: [receptorId], references: [id])\n  tipoComprobante String // 'I' (Ingreso), 'E' (Egreso), 'P' (Pago)\n  metodoPago      String? // 'PUE' o 'PPD'\n  formaPago       String?\n  subtotal        Decimal         @db.Decimal(10, 2)\n  total           Decimal         @db.Decimal(10, 2)\n\n  // SOLUCIÓN BUG 2: Guardado de identificadores oficiales\n  satUuid     String  @unique\n  facturamaId String?\n  folio       String?\n  status      String  @default(\"TIMBRADA\") // TIMBRADA, CANCELADA\n\n  // Relación para Complementos de Pago\n  complementosEmitidos PaymentComplement[] @relation(\"FacturaPagos\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// NUEVO: Modelo para Control de Complementos de Pago (REP)\nmodel PaymentComplement {\n  id              String   @id @default(uuid())\n  invoiceOrigenId String // La factura tipo 'I' (PPD) original\n  invoiceOrigen   Invoice  @relation(\"FacturaPagos\", fields: [invoiceOrigenId], references: [id])\n  cfdiPagoUuid    String   @unique // El UUID del recibo de pago timbrado\n  montoPagado     Decimal  @db.Decimal(10, 2)\n  parcialidad     Int      @default(1)\n  saldoAnterior   Decimal  @db.Decimal(10, 2)\n  saldoInsoluto   Decimal  @db.Decimal(10, 2)\n  fechaPago       DateTime\n  createdAt       DateTime @default(now())\n}\n",
  "inlineSchemaHash": "784b25243abd5bd0bbeb0f64fa62742c88154976fb1235055e90b940bf970cac",
